import os
import shutil
import tarfile
import zipfile

def create_backup(directory, format):
    if not os.path.isdir(directory):
        raise ValueError("Provided directory does not exist.")
    
    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if format not in allowed_formats:
        raise ValueError("Unsupported format. Choose from: " + ", ".join(allowed_formats))

    base_name = os.path.basename(directory)
    archive_name = f"{base_name}.{format}"
    
    if format == 'tar.gz':
        with tarfile.open(archive_name, "w:gz") as tar:
            tar.add(directory, arcname=os.path.basename(directory))
    elif format == 'tar.bz2':
        with tarfile.open(archive_name, "w:bz2") as tar:
            tar.add(directory, arcname=os.path.basename(directory))
    elif format == 'zip':
        with zipfile.ZipFile(archive_name, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(directory):
                for file in files:
                    zipf.write(os.path.join(root, file), 
                                os.path.relpath(os.path.join(root, file), 
                                os.path.join(directory, '..')))
    elif format == '7z':
        if shutil.which('7z') is None:
            raise EnvironmentError("7z is not installed.")
        shutil.make_archive(base_name, 'zip', directory)

